import logging

logger = logging.getLogger(__name__)


class UserService:
    """Service for managing user accounts."""

    def __init__(self, db):
        self.db = db

    def create_user(self, username, email, age=None):
        """Create a new user account."""
        # Validate inputs
        if not username or len(username) < 3:
            raise ValueError("Username must be at least 3 characters")
        if not email or "@" not in email:
            raise ValueError("Invalid email address")
        if age is not None and (age < 0 or age > 150):
            raise ValueError("Age must be between 0 and 150")

        logger.info(f"Creating user: {username} ({email})")

        user = {"username": username, "email": email, "age": age}

        try:
            self.db.insert("users", user)
            logger.info(f"User created successfully: {username}")
        except Exception as e:
            logger.error(f"Failed to create user {username}: {e}")
            raise

        return user

    def get_user(self, username):
        """Retrieve a user by username."""
        return self.db.find("users", {"username": username})

    def delete_user(self, username):
        """Delete a user account."""
        return self.db.delete("users", {"username": username})

